-- 🔁  RE-APPLICARE IN DEV:
--     DELETE FROM flyway_schema_history WHERE version = '38';
--     poi riavvia il backend → cleanup + re-import Billy.
-- ============================================================================

-- ── FASE 1: CLEANUP DATI OPERATIVI ───────────────────────────────────────────
-- (sicuro in prod: se non ci sono dati, le DELETE fanno 0 righe)

-- 1a. Rimuovi soft-reference dalle rate ricorrenti verso movimenti
UPDATE recurring_expense_installment
SET    movimento_id = NULL
WHERE  movimento_id IS NOT NULL;

-- 1b. Svuota movimenti (partizionata → cancella tutte le partizioni)
DELETE FROM movimenti;

-- 1c. Svuota eventi
--     (CASCADE: evento_allergie, evento_costi_diretti, evento_preventivo_tracking)
DELETE FROM eventi;

-- 1d. Svuota spese ricorrenti
--     (CASCADE: recurring_expense_installment)
DELETE FROM recurring_expense_plan;

-- 1e. Azzera saldi manuali dei conti bancari
DELETE FROM saldi_banca;

